// // This register clears on the negative edge of the clock and loads data on the positive edge when enabled.
module register_16bit(
    input [15:0] d,
    input clk,
    input en,
    input clr,
    output reg [15:0] q
);

    always @(posedge clk) begin
        if (clr)
            q <= 16'b0;
        else if (en)
            q <= d;
    end

endmodule
